import java.util.*;
public class ArrayDeepCopy {
    public static void main(String[] args) {
        int[][] a = {{1,2},{3,4}};
        int[][] b = Arrays.copyOf(a, a.length);  // shallow!
        b[0][0] = 99;
        System.out.println(a[0][0]);
        System.out.println(b[0][0]);
        b[0] = new int[]{10,20};  // reassigning row
        System.out.println(a[0][0]);
        System.out.println(b[0][0]);
    }
}
